import React, { useState } from 'react';
import Navbar              from './components/Navbar';
import HeroStory           from './components/HeroStory';
import ProfitCalculator    from './components/ProfitCalculator';
import ResourceHub         from './components/ResourceHub';
import Newsletter          from './components/Newsletter';
import Footer              from './components/Footer';
import Under30App          from './components/Under30App';
import Top30Page           from './components/Top30Page';
import ReceiptGenerator    from './components/ReceiptGenerator';
import SubscribeModal      from './components/SubscribeModal';
import AnnouncementPopup   from './components/AnnouncementPopup';

function App() {
  // ── Page routing ──────────────────────────────────────────
  // 'home' | 'under30' | 'top30' | 'receipt'
  const [activePage, setActivePage] = useState('home');

  // ── Subscribe modal ───────────────────────────────────────
  const [subscribeOpen, setSubscribeOpen] = useState(false);
  const [activeResource, setActiveResource] = useState(null);

  function openSubscribe() { setActiveResource(null); setSubscribeOpen(true); }
  function openResourceModal(r) { setActiveResource(r); setSubscribeOpen(true); }
  function closeSubscribe() { setSubscribeOpen(false); setActiveResource(null); }

  // ── Navigation helpers ────────────────────────────────────
  function goHome()    { setActivePage('home');    }
  function goUnder30() { setActivePage('under30'); }
  function goTop30()   { setActivePage('top30');   }
  function goReceipt() { setActivePage('receipt'); }

  return (
    <>
      {/* ── Global modals — always mounted so they sit above everything ── */}
      <SubscribeModal
        isOpen={subscribeOpen}
        onClose={closeSubscribe}
        resource={activeResource}
      />

      {/*
        AnnouncementPopup only shows on the home page.
        onGoToApp switches the page to under30 AND dismisses itself.
      */}
      {activePage === 'home' && (
        <AnnouncementPopup onGoToApp={goUnder30} />
      )}

      {/* ── Navbar — always visible ── */}
      <Navbar
        onUnder30WomenClick={goUnder30}
        onTop30Click={goTop30}
        onLogoClick={goHome}
        onSubscribeClick={openSubscribe}
        onResourcesClick={openSubscribe}
      />

      {/* ── Home page ── */}
      {activePage === 'home' && (
        <>
          <main className="pt-20 pb-12 max-w-7xl mx-auto px-4 sm:px-6">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8">

              <div className="lg:col-span-8 space-y-6 lg:space-y-8">
                <HeroStory />
              </div>

              <div className="lg:col-span-4 space-y-6">
                <ProfitCalculator />
                <ResourceHub onResourceClick={openResourceModal} onReceiptClick={goReceipt} />
                {/* Pass the opener down so "Join the Run" can open the modal */}
                <Newsletter onSubscribeClick={openSubscribe} />
              </div>

            </div>
          </main>
          <Footer />
        </>
      )}

      {/* ── Under30 page ── */}
      {activePage === 'under30' && (
        <div className="pt-16">
          <Under30App onBack={goHome} />
        </div>
      )}

      {/* ── Top 30 page ── */}
      {activePage === 'top30' && (
        <div className="pt-16">
          <Top30Page onBack={goHome} />
        </div>
      )}

      {/* ── Receipt Generator page ── */}
      {activePage === 'receipt' && (
        <div className="pt-16">
          <ReceiptGenerator onBack={goHome} />
        </div>
      )}
    </>
  );
}

export default App;
