import React, { useState, useEffect } from 'react';

const SUBSCRIBE_ENDPOINT = 'https://script.google.com/macros/s/AKfycbwjMCk8-m_dSeMVO6MwSY1h_N4kjTceFWSL8jR_0eGU3kK3hEgmgw-ZsWHZbfhh4J-U/exec';

export default function SubscribeModal({ isOpen, onClose, resource = null }) {
  const [email, setEmail]           = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted]   = useState(false);
  const [error, setError]           = useState('');

  useEffect(() => {
    document.body.style.overflow = isOpen ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  useEffect(() => {
    function onKey(e) { if (e.key === 'Escape') handleClose(); }
    if (isOpen) document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [isOpen]);

  function handleClose() {
    setEmail('');
    setSubmitted(false);
    setError('');
    onClose();
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setSubmitting(true);
    setError('');
    try {
      await fetch(SUBSCRIBE_ENDPOINT, {
        method:  'POST',
        mode:    'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email,
          subscribedAt: new Date().toLocaleString('en-NG', { timeZone: 'Africa/Lagos' }),
          source: 'businessrun-website',
        }),
      });
      setSubmitted(true);
    } catch (err) {
      setError('Network error. Please try again.');
    } finally {
      setSubmitting(false);
    }
  }

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center p-4"
      style={{ backgroundColor: 'rgba(0,0,0,0.45)', backdropFilter: 'blur(4px)' }}
      onClick={handleClose}
    >
      <div
        className="bg-white rounded-2xl sm:rounded-3xl w-full max-w-md relative shadow-xl"
        onClick={e => e.stopPropagation()}
      >
        {/* Close button */}
        <button
          onClick={handleClose}
          className="absolute top-4 right-4 w-8 h-8 flex items-center justify-center rounded-full text-slate-400 hover:bg-slate-100 hover:text-slate-700 transition text-xl font-light z-10"
          aria-label="Close"
        >
          ×
        </button>

        <div className="p-6 sm:p-8">
          {submitted ? (
            <div className="text-center py-4">
              <div className="w-14 h-14 bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-4">
                <i className="fas fa-check text-white text-xl"></i>
              </div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">
                {resource ? 'On its way!' : "You're in!"}
              </h3>
              <p className="text-slate-500 text-sm mb-6">
                {resource
                  ? <>The <strong className="text-slate-700">{resource}</strong> will be sent to your inbox.</>
                  : 'Welcome to the BusinessRun community. Expect sharp business insights in your inbox every week.'
                }
              </p>
              <button
                onClick={handleClose}
                className="bg-slate-800 text-white px-6 py-3 rounded-xl font-semibold text-sm hover:bg-slate-900 transition"
              >
                Done
              </button>
            </div>
          ) : (
            <>
              <div className="mb-6">
                <div className="w-10 h-10 bg-slate-700 rounded-xl flex items-center justify-center mb-4">
                  <i className={`fas ${resource ? 'fa-file-arrow-down' : 'fa-envelope'} text-white text-sm`}></i>
                </div>
                <h3 className="text-xl sm:text-2xl font-bold text-slate-900 mb-1">
                  {resource ? 'Get Your Free Resource' : 'Get the Intel.'}
                </h3>
                <p className="text-slate-500 text-sm">
                  {resource
                    ? <>Enter your email and we'll send the <strong className="text-slate-700">{resource}</strong> directly to your inbox.</>
                    : 'Join 5,000+ founders receiving weekly business insights, straight to your inbox.'
                  }
                </p>
              </div>

              <form onSubmit={handleSubmit} className="space-y-3">
                <input
                  required
                  type="email"
                  placeholder="Enter your email address"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-slate-300 outline-none"
                />

                {error && (
                  <p className="text-red-500 text-xs text-center">{error}</p>
                )}

                <button
                  type="submit"
                  disabled={submitting}
                  className="w-full bg-slate-800 text-white py-3 rounded-xl font-semibold text-sm hover:bg-slate-900 transition disabled:opacity-60 flex items-center justify-center gap-2"
                >
                  {submitting ? (
                    <>
                      <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"></path>
                      </svg>
                      Sending...
                    </>
                  ) : resource ? 'Send to My Email' : 'Join the Run'}
                </button>

                <p className="text-xs text-slate-400 text-center">
                  No spam, ever. Unsubscribe at any time.
                </p>
              </form>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
