import React, { useState, useRef, useEffect } from 'react';

function Navbar({ onUnder30WomenClick, onTop30Click, onLogoClick, onSubscribeClick, onResourcesClick }) {
  const [under30Open, setUnder30Open]       = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    function handleClickOutside(e) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setUnder30Open(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    function handleResize() {
      if (window.innerWidth >= 768) setMobileMenuOpen(false);
    }
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  function handleUnder30WomenClick() {
    setUnder30Open(false);
    setMobileMenuOpen(false);
    onUnder30WomenClick();
  }

  function handleLogoClick() {
    setMobileMenuOpen(false);
    setUnder30Open(false);
    onLogoClick();
  }

  function handleSubscribeClick() {
    setMobileMenuOpen(false);
    onSubscribeClick();
  }

  return (
    <nav className="fixed top-0 w-full z-50 nav-blur border-b border-slate-200">

      <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">

        {/* Logo */}
        <button
          onClick={handleLogoClick}
          className="flex items-center space-x-2 focus:outline-none group"
          aria-label="Go to homepage"
        >
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-sm group-hover:bg-blue-700 transition">
            B
          </div>
          <span className="text-xl font-extrabold tracking-tight text-slate-800 group-hover:text-blue-600 transition">
            BusinessRun
          </span>
        </button>

        {/* Desktop nav links */}
        <div className="hidden md:flex items-center space-x-8 text-sm font-semibold text-slate-600">
          <a href="#stories"   className="hover:text-slate-900 transition">Stories</a>
          <a href="#tools"     className="hover:text-slate-900 transition">Tools</a>
          <button onClick={onResourcesClick} className="hover:text-slate-900 transition focus:outline-none">Resources</button>

          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setUnder30Open(p => !p)}
              className="flex items-center gap-1 hover:text-blue-600 transition focus:outline-none"
            >
              Under30
              <i className={`fas fa-chevron-down text-xs transition-transform duration-200 ${under30Open ? 'rotate-180' : ''}`}></i>
            </button>

            {under30Open && (
              <div className="absolute top-full left-0 mt-3 w-56 bg-white rounded-2xl shadow-lg border border-slate-100 py-2 z-50">
                <button
                  onClick={handleUnder30WomenClick}
                  className="w-full text-left flex items-center gap-3 px-4 py-3 text-sm text-slate-700 font-medium hover:bg-slate-50 hover:text-slate-900 transition"
                >
                  <span className="w-7 h-7 bg-slate-100 text-slate-500 rounded-lg flex items-center justify-center flex-shrink-0">
                    <i className="fas fa-rocket text-xs"></i>
                  </span>
                  Under30Women
                </button>
                <button
                  onClick={() => { setUnder30Open(false) }}
                  className="w-full text-left flex items-center gap-3 px-4 py-3 text-sm text-slate-700 font-medium hover:bg-slate-50 hover:text-slate-900 transition"
                >
                  <span className="w-7 h-7 bg-slate-100 text-slate-500 rounded-lg flex items-center justify-center flex-shrink-0">
                    <i className="fas fa-trophy text-xs"></i>
                  </span>
                  Top 30 List
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Right */}
        <div className="flex items-center gap-3">
          <button
            onClick={handleSubscribeClick}
            className="hidden md:block bg-slate-800 text-white px-5 py-2 rounded-full text-sm font-semibold hover:bg-slate-900 transition"
          >
            Subscribe
          </button>

          <button
            onClick={() => setMobileMenuOpen(p => !p)}
            className="md:hidden flex flex-col justify-center items-center w-10 h-10 rounded-lg hover:bg-slate-100 transition gap-1.5"
            aria-label="Toggle menu"
          >
            <span className={`block h-0.5 w-6 bg-slate-800 transition-all duration-300 ${mobileMenuOpen ? 'rotate-45 translate-y-2' : ''}`}></span>
            <span className={`block h-0.5 w-6 bg-slate-800 transition-all duration-300 ${mobileMenuOpen ? 'opacity-0' : ''}`}></span>
            <span className={`block h-0.5 w-6 bg-slate-800 transition-all duration-300 ${mobileMenuOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      {mobileMenuOpen && (
        <div className="md:hidden bg-white border-t border-slate-100 px-4 py-4 space-y-1 shadow-md">
          <a href="#stories"   onClick={() => setMobileMenuOpen(false)} className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-slate-700 hover:bg-slate-50 transition">
            <i className="fas fa-newspaper w-4 text-slate-400"></i> Stories
          </a>
          <a href="#tools"     onClick={() => setMobileMenuOpen(false)} className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-slate-700 hover:bg-slate-50 transition">
            <i className="fas fa-calculator w-4 text-slate-400"></i> Tools
          </a>
          <button onClick={() => { setMobileMenuOpen(false); onResourcesClick(); }} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-slate-700 hover:bg-slate-50 transition text-left">
            <i className="fas fa-book w-4 text-slate-400"></i> Resources
          </button>

          <div className="pt-1 border-t border-slate-100 mt-1">
            <p className="px-4 py-2 text-xs font-bold text-slate-400 uppercase tracking-widest">Under30</p>
            <button
              onClick={handleUnder30WomenClick}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-slate-700 hover:bg-slate-50 hover:text-slate-900 transition"
            >
              Under30Women
            </button>
            <button
              onClick={() => { setMobileMenuOpen(false) }}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-slate-700 hover:bg-slate-50 transition"
            >
              Top 30 List
            </button>
          </div>

          <div className="pt-2">
            <button
              onClick={handleSubscribeClick}
              className="w-full bg-slate-800 text-white py-3 rounded-xl text-sm font-semibold hover:bg-slate-900 transition"
            >
              Subscribe
            </button>
          </div>
        </div>
      )}
    </nav>
  );
}

export default Navbar;
