import React, { useState, useEffect } from 'react';

// ─────────────────────────────────────────────────────────────
// AnnouncementPopup
//
// Appears automatically a short moment after the user lands on
// the homepage. Informs them about the Under30Women application.
//
// Props:
//   onGoToApp — function, navigates user to the Under30 landing page
// ─────────────────────────────────────────────────────────────
export default function AnnouncementPopup({ onGoToApp }) {
  const [visible, setVisible] = useState(false);
  const [dismissed, setDismissed] = useState(false);

  // Show the popup 1.5 seconds after the page loads —
  // gives the page time to fully render before interrupting.
  useEffect(() => {
    const timer = setTimeout(() => setVisible(true), 10000);
    return () => clearTimeout(timer);
  }, []);

  // Lock body scroll while popup is visible
  useEffect(() => {
    if (visible && !dismissed) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [visible, dismissed]);

  // Close on Escape key
  useEffect(() => {
    function onKey(e) {
      if (e.key === 'Escape') dismiss();
    }
    if (visible && !dismissed) document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [visible, dismissed]);

  function dismiss() {
    setDismissed(true);
    document.body.style.overflow = '';
  }

  function handleGoToApp() {
    dismiss();
    onGoToApp();
  }

  if (!visible || dismissed) return null;

  return (
    <div
      className="fixed inset-0 z-[90] flex items-center justify-center p-4"
      style={{ backgroundColor: 'rgba(0,0,0,0.55)', backdropFilter: 'blur(4px)' }}
      onClick={dismiss}
    >
      <div
        className="bg-white rounded-2xl sm:rounded-3xl w-full max-w-md relative shadow-2xl overflow-hidden"
        onClick={e => e.stopPropagation()}
      >
        {/* Header banner — slate to match site palette */}
        <div className="bg-slate-900 px-6 py-4 sm:py-5">
          <div className="flex items-center justify-between">
            <span className="text-slate-400 text-xs font-semibold uppercase tracking-widest">
              Now Open
            </span>
            <button
              onClick={dismiss}
              className="w-7 h-7 flex items-center justify-center rounded-full bg-white/10 text-white hover:bg-white/20 transition text-lg font-light leading-none"
              aria-label="Close announcement"
            >
              ×
            </button>
          </div>
          <h2 className="text-white font-bold text-lg sm:text-xl mt-2 leading-snug">
            Under30Women in Business<br />Mentorship 2026
          </h2>
        </div>

        {/* Body */}
        <div className="px-6 py-5 sm:py-6">
          <p className="text-slate-500 text-sm sm:text-base leading-relaxed mb-5">
            Applications are now open for the <strong className="text-slate-700">2026 Under30Women in Business
            Mentorship Cohort</strong>. We are looking for exceptional female founders
            across Africa ready to build scalable, self-reliant enterprises.
          </p>

          <div className="flex flex-col sm:flex-row gap-3">
            {/* Primary CTA */}
            <button
              onClick={handleGoToApp}
              className="flex-1 bg-slate-800 text-white py-3 px-4 rounded-xl font-semibold text-sm hover:bg-slate-900 transition flex items-center justify-center gap-2"
            >
              Apply Now
              <i className="fas fa-arrow-right text-xs"></i>
            </button>

            {/* Secondary — dismiss */}
            <button
              onClick={dismiss}
              className="flex-1 bg-slate-100 text-slate-500 py-3 px-4 rounded-xl font-semibold text-sm hover:bg-slate-200 transition"
            >
              Maybe Later
            </button>
          </div>

          <p className="text-xs text-slate-400 text-center mt-4">
            Applications close 22nd April 2026
          </p>
        </div>
      </div>
    </div>
  );
}
